// String: "abcabcbb"
// Find the length of the LONGEST SUBSTRING with NO repeating characters

// Clue 1: "substring" + "longest" -> Sliding Window
// Clue 2: "no repeating characters" -> need FAST lookup of what's currently in the window -> Hashing

#include <iostream>
#include <string>
#include <unordered_set>

using namespace std;

int lengthOfLongestSubstring(string s)
{
    unordered_set<char> window; // characters currently inside the sliding window
    int left = 0;
    int best = 0;

    for (int right = 0; right < (int)s.size(); right++)
    {
        while (window.count(s[right])) // duplicate found -> shrink from the left
        {
            window.erase(s[left]);
            left++;
        }

        window.insert(s[right]);
        best = max(best, right - left + 1);
    }

    return best;
}

int main()
{
    cout << lengthOfLongestSubstring("abcabcbb") << endl;

    return 0;
}

